"""Run reusable data-quality sanity checks and emit JSON results."""

from __future__ import annotations

import ast
import json
import re
import sys
from pathlib import Path
from typing import Any

import pandas as pd

PROJECT_ROOT = Path(__file__).resolve().parents[1]
SOURCE_OF_TRUTH_PATH = PROJECT_ROOT / "docs" / "metrics_definitions.md"
DATE_COLUMN_NAMES = {"date", "signup_date", "last_active", "created_at", "updated_at"}
TRANSACTION_FILE_PATTERN = "transactions*.csv"


def read_text(path: Path) -> str:
    """Read UTF-8 text from a project file."""
    return path.read_text(encoding="utf-8")


def extract_churn_threshold_definition(path: Path) -> dict[str, Any]:
    """Extract authoritative churn thresholds from the metrics definition document."""
    text = read_text(path)
    transaction_match = re.search(
        r"no transactions in last\s+(\d+)\s+days", text, flags=re.IGNORECASE
    )
    account_match = re.search(
        r"no account activity.*?in last\s+(\d+)\s+days", text, flags=re.IGNORECASE
    )
    if transaction_match is None:
        raise ValueError(f"Could not find transaction inactivity threshold in {path}")

    return {
        "source": str(path.relative_to(PROJECT_ROOT)),
        "transaction_inactivity_days": int(transaction_match.group(1)),
        "account_activity_days": int(account_match.group(1)) if account_match else None,
    }


def extract_config_churn_threshold(path: Path) -> int | None:
    """Extract CHURN_DEFINITION['days_inactive'] without relying on remembered values."""
    tree = ast.parse(read_text(path))
    for node in tree.body:
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and target.id == "CHURN_DEFINITION":
                    value = ast.literal_eval(node.value)
                    return int(value["days_inactive"])
    return None


def extract_integer_constant(path: Path, constant_name: str) -> int | None:
    """Extract a top-level integer constant from a Python source file."""
    tree = ast.parse(read_text(path))
    for node in tree.body:
        if isinstance(node, ast.Assign):
            for target in node.targets:
                if isinstance(target, ast.Name) and target.id == constant_name:
                    return int(ast.literal_eval(node.value))
    return None


def check_churn_thresholds() -> dict[str, Any]:
    """Compare churn-threshold constants against the documented source of truth."""
    definition = extract_churn_threshold_definition(SOURCE_OF_TRUTH_PATH)
    expected = definition["transaction_inactivity_days"]
    observed = [
        {
            "name": "CHURN_DEFINITION.days_inactive",
            "path": "src/config.py",
            "value": extract_config_churn_threshold(PROJECT_ROOT / "src" / "config.py"),
        },
        {
            "name": "CHURN_THRESHOLD",
            "path": "src/data_validator.py",
            "value": extract_integer_constant(PROJECT_ROOT / "src" / "data_validator.py", "CHURN_THRESHOLD"),
        },
        {
            "name": "DEFAULT_CHURN_THRESHOLD_DAYS",
            "path": "src/analysis_v2.py",
            "value": extract_integer_constant(
                PROJECT_ROOT / "src" / "analysis_v2.py", "DEFAULT_CHURN_THRESHOLD_DAYS"
            ),
        },
    ]

    for item in observed:
        item["matches_source_of_truth"] = item["value"] == expected

    return {
        "status": "pass" if all(item["matches_source_of_truth"] for item in observed) else "fail",
        "source_of_truth": definition,
        "observed_constants": observed,
    }


def transaction_files() -> list[Path]:
    """Return transaction CSV files from raw and processed data directories."""
    files: list[Path] = []
    for directory in (PROJECT_ROOT / "data" / "raw", PROJECT_ROOT / "data" / "processed"):
        if directory.exists():
            files.extend(sorted(directory.glob(TRANSACTION_FILE_PATTERN)))
    return files


def csv_files() -> list[Path]:
    """Return project CSV files from raw and processed data directories."""
    files: list[Path] = []
    for directory in (PROJECT_ROOT / "data" / "raw", PROJECT_ROOT / "data" / "processed"):
        if directory.exists():
            files.extend(sorted(directory.glob("*.csv")))
    return files


def load_csv(path: Path) -> pd.DataFrame:
    """Load a CSV file as strings for validation checks."""
    return pd.read_csv(path, dtype=str, keep_default_na=True, low_memory=False)


def check_duplicate_residue() -> dict[str, Any]:
    """Check transaction files for duplicate transaction_id residue."""
    file_results: list[dict[str, Any]] = []
    for path in transaction_files():
        df = load_csv(path)
        relative_path = str(path.relative_to(PROJECT_ROOT))
        if "transaction_id" not in df.columns:
            file_results.append(
                {
                    "path": relative_path,
                    "status": "warn",
                    "row_count": int(len(df)),
                    "duplicate_residue_count": None,
                    "message": "transaction_id column missing",
                }
            )
            continue

        duplicate_count = int(df.duplicated(subset=["transaction_id"]).sum())
        file_results.append(
            {
                "path": relative_path,
                "status": "pass" if duplicate_count == 0 else "fail",
                "row_count": int(len(df)),
                "duplicate_residue_count": duplicate_count,
                "unique_transaction_ids": int(df["transaction_id"].nunique(dropna=True)),
            }
        )

    return {
        "status": "pass" if all(item["status"] == "pass" for item in file_results) else "fail",
        "files": file_results,
    }


def check_date_columns() -> dict[str, Any]:
    """Check parseability and range sanity for known date columns."""
    file_results: list[dict[str, Any]] = []
    for path in csv_files():
        df = load_csv(path)
        column_results: list[dict[str, Any]] = []
        for column in [name for name in df.columns if name in DATE_COLUMN_NAMES]:
            parsed = pd.to_datetime(df[column], errors="coerce", format="mixed")
            non_null_count = int(df[column].notna().sum())
            invalid_count = int(parsed.isna().sum() - df[column].isna().sum())
            valid_values = parsed.dropna()
            column_results.append(
                {
                    "column": column,
                    "status": "pass" if invalid_count == 0 else "fail",
                    "non_null_count": non_null_count,
                    "invalid_count": invalid_count,
                    "min_date": valid_values.min().date().isoformat() if not valid_values.empty else None,
                    "max_date": valid_values.max().date().isoformat() if not valid_values.empty else None,
                }
            )

        if column_results:
            file_results.append(
                {
                    "path": str(path.relative_to(PROJECT_ROOT)),
                    "status": "pass" if all(item["status"] == "pass" for item in column_results) else "fail",
                    "date_columns": column_results,
                }
            )

    return {
        "status": "pass" if all(item["status"] == "pass" for item in file_results) else "fail",
        "files": file_results,
    }


def build_report() -> dict[str, Any]:
    """Build the complete quality-check report."""
    checks = {
        "duplicate_residue": check_duplicate_residue(),
        "date_columns": check_date_columns(),
        "churn_threshold": check_churn_thresholds(),
    }
    return {
        "status": "pass" if all(check["status"] == "pass" for check in checks.values()) else "fail",
        "project_root": str(PROJECT_ROOT),
        "checks": checks,
    }


def main() -> int:
    """Emit quality-check JSON and return a CI-friendly exit code."""
    try:
        report = build_report()
    except Exception as exc:
        report = {"status": "error", "error": str(exc)}
        print(json.dumps(report, indent=2, sort_keys=True))
        return 2

    print(json.dumps(report, indent=2, sort_keys=True))
    return 0 if report["status"] == "pass" else 1


if __name__ == "__main__":
    raise SystemExit(main())

